var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"흐흥흥~ 다음 배달지로 출발해 볼까나?","JPN":"フンフフ～ン♪　次のお届け先に出発しようかな？","ENG":"La, la, la. Let's go to the next delivery address.","TWN":"呵呵呵～出發前往下一個配送地點吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"…"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_QM","text":{"KOREA":"지금이다!","JPN":"今だ！","ENG":"Now!","TWN":"趁現在！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_ARROW"},{"id":"L8_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"우앗?! 줄이 발에 걸렸다…?!","JPN":"わっ！？　足に紐が引っかかった……！？","ENG":"Wah! I tripped over a string...?","TWN":"啊咧？！腳絆到繩子…？！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_WHIP"},{"id":"L13_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_QM","text":{"KOREA":"헤헤, 드디어 잡았다.","JPN":"ヘヘッ、やっと捕まえた。","ENG":"Heh heh! Finally, we got you!","TWN":"嘿嘿，終於抓到了吧！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_NPC_FOOLSDAY_QM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"응?","JPN":"え？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_NPC_FOOLSDAY_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"꺄아아! 야한 그림체를 가진 요요를 휘두르는 해적이다!","JPN":"きゃー！　ヨーヨーを振り回すエロい絵柄の海賊だ！","ENG":"Kyaaak! A pirate swinging a yoyo with a lewd art style on it!","TWN":"哇啊啊！是玩溜溜球的海盜！而且溜溜球上還有色情圖片！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_NPC_FOOLSDAY_QM","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L21_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_QM","text":{"KOREA":"해적은 아니고 공무원이야.","JPN":"海賊ではなく、公務員だ。","ENG":"I'm not a pirate. I'm a government official.","TWN":"我是不是海盜，是公務員。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_QM","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_QM","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"어라, 두 사람? 당신들은 누구시죠?","JPN":"あれ、二人も？　どちら様ですか？","ENG":"Err, you two. Who are you?","TWN":"嗯？是平行時空嗎？你們是誰？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_QM","text":{"KOREA":"훗, 우리가 누구냐고 물으신다면…","JPN":"ふふ、なんだかんだと聞かれたら……","ENG":"Heh, prepare for trouble.","TWN":"呵，既然你誠心誠意地發問了…"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_QM","text":{"KOREA":"우주의 평화를 지키는…!","JPN":"この宇宙の平和を守る……！","ENG":"To protect the world from devastation...!","TWN":"為了守護宇宙的和平…！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_QM","face":"UNIT_LAUGH"},"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L27_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"외우주 통합질서 특수 검거반 6팀 L 그리고 A다.","JPN":"外宇宙総合秩序特殊捜査課6班のM、そしてAだ。","ENG":"L and A Of Outer Space United Order Special Police Team 6.","TWN":"為了維護外太空的秩序，我們是特殊刑警大隊第6小隊的L和A！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_QM","face":"UNIT_LAUGH"},"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"당신을 체포하러 왔어.","JPN":"お前を逮捕しに来た。","ENG":"We came to arrest you.","TWN":"我們是來逮捕你的！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_QM","face":"UNIT_IDLE"},"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"야 야, 제일 재밌는 부분인데 그렇게 평범하게 소개하면 어떡해?","JPN":"ちょっとちょっと、一番肝心なところなのにそんな地味な紹介でいいわけ？","ENG":"Hey! That was the funniest part, and you ruined it by saying it in such a monotone.","TWN":"喂喂喂，這段是最精彩的部分欸，怎麼被你介紹得那麼雞肋？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_SERIOUS"},"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"질질 끌면 아이스크림 녹아. 빨리 하고 끝내.","JPN":"ダラダラするとアイスクリームが溶けてしまう。さっさと終わらせよう。","ENG":"Let's not drag on. The ice cream is melting. Let's get this over with.","TWN":"再這樣拖拖拉拉的，冰淇淋都要融化了，趕快搞定吧！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_SERIOUS"},"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"쳇, 시시하긴.","JPN":"ちっ、つまんない。","ENG":"Bah, spoilsport.","TWN":"嗟，真沒意思！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_HATE"},"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"와아, 우주 경찰이요? 신기하네요. 저 처음 봤어요!","JPN":"わぁ、宇宙警察ですか？　すごーい、初めてみました！","ENG":"Whoa, are you space cops? Holy cow, I've never met one before!","TWN":"哇～是宇宙警察嗎？好奇妙喔，我還是第一次知道有宇宙警察呢！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L35_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"당신들이 타고 온 우주선 보여주실 수 있나요? 우주 권총? 우주 광선검은요? 지금 가지고 계신 건 우주 요요인가요? 그건 우주 스케이트보드죠? 저 타봐도 되나요?","JPN":"刑事さんが乗ってきた宇宙船、見せてくれませんか？　宇宙ブラスター？　宇宙ビームソードは？ 今持っていらっしゃるのは宇宙ヨーヨーですか？　それは宇宙スケートボードですよね？　乗ってみてもいいですか！？","ENG":"Could you show me your spaceship? Space guns? How about space lightsabers? Is that a space yoyo you have? That's a space skateboard, isn't it? May I try it?","TWN":"可以借我看一下你們的宇宙船嗎？還有宇宙槍呢？跟那個宇宙光劍？然後你手裡拿的是宇宙溜溜球嗎？那個是宇宙滑板嗎？我可以玩玩看嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"시끄러.","JPN":"うるさい！","ENG":"Shut up.","TWN":"吵死了！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"넵.","JPN":"はいっ。","ENG":"Okie.","TWN":"抱歉！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"크흠-","JPN":"こほん。","ENG":"Ahem.","TWN":"咳咳-"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"라라 예거. 당신이 세계선을 넘어다니며 물건들을 빼돌리는 범죄를 저질러서 데리러 왔어.","JPN":"ララ・イェーガー。あんたは世界線を越えてあらゆるものを横流しする罪を犯しているため逮捕する。","ENG":"Lara Jaeger, we came to pick you up for illegally crossing worldlines and stealing goods.","TWN":"拉拉·伊格，你涉嫌越過世界界線盜取物品，我們現在要逮捕你。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"우주 영장이라면 실컷 만지게 해줄 테니 확인해 보던가.","JPN":"宇宙逮捕令状なら思う存分触らせてやるから、確認してもいいよ。","ENG":"We can show you your space warrant if you want.","TWN":"你放心，我們是有通緝令的，睜大你的眼睛好好看清楚！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"네? 범죄요?! 저는 일개 배달원으로서 음식을 배달하고 있었을 뿐인데요?!","JPN":"え？　犯罪ですか！？　私はただの配達員で料理を届けていただけですよ！？","ENG":"Excuse me? I illegally did what? I'm just a deliverywoman—I was only delivering food!","TWN":"什麼？犯罪？我只是個小小外送員，而且送的都是吃的欸？！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"바로 그게 문제야, 프로메테우스 씨.","JPN":"それが問題なんだよ、プロメテウスさん。","ENG":"That's the problem, Miss Prometheus.","TWN":"問題就出在這裡，普羅米修斯。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"우주 통합 규칙 1조 1항. 시공간을 넘어 무언가를 전달함으로써 우주의 섭리를 거스르지 말 것.","JPN":"宇宙総合規則1条1項。時空間を越えて何かを移動させることで、宇宙の摂理に逆らわないこと。","ENG":"United Space Rule 1 Paragraph 1: Do not change the course of the universe by delivering something across spacetime.","TWN":"宇宙規章第一條第一項，不得因穿越時空傳達東西而違反宇宙法則。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"우리 세계에서 그걸 어기면 그… 과거와 미래가 어긋나는 일이… 뭐라고 하더라?","JPN":"この世界でそれに反したらその……過去と未来が食い違うこと……何て言うんだっけ？","ENG":"Or you'll dislocate the future from the past—what do you call this again?","TWN":"你在我們的世界違反這項條例…導致過去和未來發生衝突…那個叫什麼？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"타임 패러독스.","JPN":"タイムパラドックス。","ENG":"Time paradox.","TWN":"時間悖論。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"아, 그래! 그런 걸 유발해서 온 우주 전체가 붕괴될 수도 있다고. 알아?","JPN":"そう、それ！　それをもたらして、全宇宙が崩壊する事態になり得るからね。わかった？","ENG":"Oh, yeah! You'll cause something like that, destroying the entire universe. Get it?","TWN":"對啦！就是那個！這會導致全宇宙的混亂，你知不知罪！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"모, 몰랐어요. 죄송해요.","JPN":"し、知りませんでした。すみません。","ENG":"I-I didn't know. I'm sorry.","TWN":"我…我不知道會這麼嚴重，對不起。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"뭐, 좋아. 초범이니 정상 참작해서 100년 정도만 외우주감옥에 가두는 걸로 할까?","JPN":"まあ、わかったならいいわ。初犯だし情状酌量で100年くらい外宇宙刑務所に服役させることにするか。","ENG":"Well, alright. Since you're a first-timer, maybe we'll lock you up in the outer space prison for just 100 years.","TWN":"嗯，好吧，念在你是初犯，就判你在外太空監獄裡服刑100年吧？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"100년?! 그건 무기징역이잖아요!","JPN":"100年！？　それってつまり無期懲役じゃないですか！","ENG":"100 years? That's a life sentence!","TWN":"100年？！這不就是終身監禁的意思！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"온 차원을 멸망시킬 뻔한 범죄자에겐 이 정도도 싸게 먹히는 편이야.","JPN":"全次元を滅ぼしそうになった犯罪者には、この程度の刑でも軽い方なんだけど。","ENG":"You should be grateful we're not killing you right on the spot. You almost destroyed the entire universe.","TWN":"你可是差點毀掉整個次元的罪犯，這樣已經算輕判好嗎！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"우린 너 때문에 모처럼의 회식날인데도 긴급출동해야 했거든?","JPN":"私たちはあんたのせいでせっかくのパーティの日に緊急出動したんだよ？","ENG":"Also, we had to come here to catch you on our rare company dining day.","TWN":"都是你害我們好不容易可以聚餐，結果變成要緊急出動！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"게다가 우리 아이스크림도 녹게 만들었고 말이지.","JPN":"しかも私たちのアイスクリームも溶けてしまった。","ENG":"Let's not forget our melting ice cream, either.","TWN":"還害我們的冰淇淋融化！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"그, 그럴 수가…","JPN":"そ、そんな……","ENG":"N-no way...","TWN":"怎…怎麼這樣…"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"아, 너무 걱정 마. 우주의 시간은 상대적인 거니까. 꼬부랑 할머니가 되기 전엔 나갈 수 있을 걸?","JPN":"まあまあ、そんなに心配することないさ。宇宙の時間は相対的なものだから。おばあちゃんになる前には出られると思うよ？","ENG":"Ah, don't worry too much. Time in outer space is relative. You'll be out of prison at least before you become too old to walk.","TWN":"不過你放心啦！宇宙的時間是相對的，應該在你變成白髮蒼蒼的老奶奶之前就能出獄了吧？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"으으~ 좀 봐주세요, 경찰 나으리.","JPN":"うう……勘弁してくださいよ、刑事様～！","ENG":"Aww, please take pity on me, officers.","TWN":"嗚嗚～警察大人，放我一馬吧～"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"아직 연애도 결혼도 못 해봤는데, 한 시간만 여유를 주시면 안 될까요?","JPN":"仕事に追われてまだ恋も結婚もしてないのに……1時間だけ時間をいただけませんか？","ENG":"I haven't even had a boyfriend, let alone gotten married. Can't you at least give me an hour?","TWN":"我母胎單身，婚也沒結過，可以給我一小時的時間嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"그렇게는 안돼.","JPN":"そうはいかないよ。","ENG":"No.","TWN":"不可以。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"아니, 애초에 고작 한 시간 가지고 뭘 어떻게 할 작정인 거야?","JPN":"いや、そもそもたったの1時間で何をどうするつもり？","ENG":"Even if we gave you an hour, what could you do in such a short amount of time?","TWN":"我說，一小時是能幹嘛啦？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"첫 눈에 반했는데 궁합이 잘 맞으면 어떻게든 되지 않을까요?","JPN":"一目惚れして相性さえよければ何とかなるんじゃないですかね？","ENG":"Maybe I'd fall in love at first sight.","TWN":"萬一一見鍾情後又合得來的話，說不定有機會發生什麼事啊？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"이달의 사주에서 연애운이 좋다길래 나름 기대하고 있거든요!","JPN":"今月の占いで恋愛運がアップと出ていたのでちょっと期待してたんです！","ENG":"My fortune of the month says I've got love luck.","TWN":"這個月星座大師說我走戀愛運，人家很期待欸！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"100년 뒤의 연애운이나 미리 확인해 두던가.","JPN":"100年先の恋愛運を確かめておくのをおすすめするよ。","ENG":"Why don't you check your fortune of 100 years from now?","TWN":"那你可以先打聽好100年後的戀愛運。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"힝, 그럴 수가아…","JPN":"ひーん、そんなぁ……","ENG":"Hnngg... No...","TWN":"嗚，怎麼這樣…"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"하다못해 오늘의 마지막 배달이라도 마치고 가면 안 될까요?","JPN":"せめて今日の最後のお届けだけでも済ませてから行くのはダメですか？","ENG":"Then, can't you at least let me make my last delivery for the day?","TWN":"那不然，還是可以讓我完成今天的最後一筆訂單嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"저희 배달부들은 신속정확이 생명이라고요.","JPN":"私たち配達員は、迅速かつ正確が命なんです。","ENG":"We carriers live for speed and accuracy.","TWN":"外送員的責任就是要使命必達！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"배달? 뭘 배달하고 있던 중인데?","JPN":"お届け？　何を配達してたの？","ENG":"Your last delivery? What are you delivering?","TWN":"外送？你剛是在送什麼？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"으음… 수퍼 프라임 등급 우주 소고기 한 박스네요.","JPN":"えっと……スーパープライムランクの宇宙牛肉一頭分です。","ENG":"Mm... A box of Super Prime-grade space beef.","TWN":"嗯…極品宇宙牛肉一盒。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"배달주소는 외우주 통합질서 경찰서 (뒷문)으로 되어 있어요.","JPN":"配達先は外宇宙総合秩序警察署(裏門)と書いていますね。","ENG":"The delivery address is Outer Space United Order Police Station (rear gate).","TWN":"外送的地址是外太空警署(後門)。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"아, 우리 거네.","JPN":"あ、私たちが頼んだやつか。","ENG":"Oh, that's ours.","TWN":"欸，是我們的！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"아앗! 뭐야! 완전 내로남불이잖아요, 그거!","JPN":"え？　何なんですかぁ！　それって頼んだ側も犯罪になるんでしょー？","ENG":"What? No! That's a double standard!","TWN":"什麼嘛！你們這是只許州官放火，不許百姓點燈嗎！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L30_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"뭔가 온다.","JPN":"何かが来る。","ENG":"Something's coming.","TWN":"好像有什麼東西？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Huh?","TWN":"什麼？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"우왓, 깜짝이야. 저건 또 뭐야?","JPN":"わっ、ビックリした。あれはなに？","ENG":"Wah! Geez! What the heck are those?","TWN":"哇啊！嚇死我了，那又是什麼？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"침식체야. 배달부에게서 다른 차원의 냄새를 맡고 온 것 같군.","JPN":"侵食体だ。この配達員からする他の次元の匂いを嗅ぎつけて来たようだな。","ENG":"C.O. They must have detected the otherworldly smell of the deliverywoman.","TWN":"是侵蝕體，應該是被她身上其他次元的味道吸引來的。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"쳇, 벌써 둘러싸였나? 이제 와서 도망치긴 어렵겠는데?","JPN":"ちっ、もう囲まれたのか。今更逃げるのは厳しそうじゃない？","ENG":"Bah, we're already surrounded. I don't think we can run.","TWN":"可惡，我們被包圍了嗎？這下逃不掉了吧？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"제가 도와드릴게요!","JPN":"私が力になります！","ENG":"Let me help you!","TWN":"我來幫你們吧！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_SERIOUS"},"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"응? 네가? 할 수 있겠어?","JPN":"え？　あんたが？　できるの？","ENG":"Huh? You? How?","TWN":"嗯？就憑你？你可以嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_SURPRISE"},"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"저 이래봬도 카운터거든요! 침식체들 유인하는 것정도는 할 수 있어요!","JPN":"こう見えてもカウンターなんですよ！　侵食体を引き付けることぐらいできます！","ENG":"I may not look it, but I'm a Counter. I can at least lure away the C.O.","TWN":"你不要看我這樣，我可是制裁者呢！要引開侵蝕體是沒問題的！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_SURPRISE"},"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"협조 고맙군. 감사의 표시로 무기징역 건은 없던 일로 해두지.","JPN":"それは助かる。無期懲役の件は無しにしておこう。","ENG":"Thank you for your cooperation. In return, we'll forget about your life sentence.","TWN":"謝謝你的幫忙。就撤銷你的無期徒刑當作謝禮吧！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_SURPRISE"},"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"역시 화끈하시네요! 이것이 우주 부패경찰!","JPN":"さすが太っ腹！　これぞ宇宙汚職警察官！","ENG":"You're so generous! Thank you, corrupt space cops!","TWN":"真是爽快！你這個宇宙腐敗警察！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_SURPRISE"},"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"야, 이것들아. 저리 안 꺼져?","JPN":"まったく、近付くんじゃない！","ENG":"Hey, nasties. Go away!","TWN":"喂，你們這些臭傢伙，快給我滾開！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"쳇, 이럴 때 반장은 어딨는 거야?","JPN":"ちっ、こんな時に班長はどこにいるの？","ENG":"Gah, our captain is never around when we need him the most.","TWN":"嗟，現在這種正需要班長的時候，他是跑哪去啦？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"반장은 마트에 장보러 갔으니까, 지금쯤 야채를 사고 있겠지.","JPN":"班長はスーパーに買い出しに行った。今頃野菜コーナーにいるだろう。","ENG":"He went grocery shopping. I bet he's looking at vegetables right now.","TWN":"班長去大賣場，現在應該在挑蔬菜吧？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"그럼 우리끼리 해결을 봐야겠네. 소고기에 마늘, 상추는 중대 사항이니까.","JPN":"それなら私たちで解決するしかないか。肉に副菜は欠かせないしね。","ENG":"Then, we'll have to take care of this on our own. We can't eat steak without green beans or broccoli.","TWN":"那我們就自己解決吧！畢竟烤肉不能沒有大蒜和生菜！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_PRIDE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L49_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"동감이다. 아이스크림이 녹기 전에 끝내자고.","JPN":"同感だ。アイスクリームが溶ける前に終わらせよう。","ENG":"No, we can't. Let's get this over with before the ice cream completely melts.","TWN":"完全正確。在冰淇淋融化前搞定吧！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"}]`);export{e as default};